const now = new Date();
const runId = now.toISOString().replace(/[^0-9]/g, '');
const sender = 'hello.wieland.collective+manual-test@gmail.com';

return [{
  json: {
    from: 'Manual Test <' + sender + '>',
    to: 'hello.wieland.collective@gmail.com',
    subject: 'Manual responder workflow test ' + now.toISOString(),
    date: now.toISOString(),
    textPlain: [
      'Hello Wieland Collective,',
      '',
      'This is a manual test email for the automatic responder workflow.',
      'Please answer as if I am asking what services you offer and how to start a project.',
      '',
      'Thanks!',
      'Manual Test',
    ].join('\n'),
    textHtml: '',
    cc: '',
    metadata: {
      'message-id': '<manual-test-' + runId + '@n8n.local>',
    },
    attributes: {
      uid: Number(runId.slice(-12)),
    },
  },
}];

const ACCOUNT_EMAIL = 'hello.wieland.collective@gmail.com';

const stripHtml = (value) => String(value ?? '')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

const normalizeWhitespace = (value) => String(value ?? '')
  .replace(/\r\n/g, '\n')
  .replace(/[\t ]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const hashText = (value) => {
  let h1 = 0xdeadbeef;
  let h2 = 0x41c6ce57;
  for (let i = 0; i < value.length; i += 1) {
    const ch = value.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507) ^ Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507) ^ Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  return ((h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0'));
};

const extractEmail = (value) => {
  if (!value) return '';
  if (typeof value === 'object') {
    if (Array.isArray(value.value) && value.value[0]?.address) {
      return String(value.value[0].address).toLowerCase();
    }
    if (value.address) return String(value.address).toLowerCase();
    if (value.text) value = value.text;
  }

  const text = String(value);
  const bracketAddress = text.match(/<([^>]+)>/);
  const candidate = bracketAddress?.[1] ?? text;
  const match = candidate.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return match ? match[0].toLowerCase() : '';
};

const formatAddress = (value) => {
  if (!value) return '';
  if (typeof value === 'object') {
    if (value.text) return String(value.text);
    if (Array.isArray(value.value)) {
      return value.value
        .map((entry) => entry?.address ? (entry.name ? entry.name + ' <' + entry.address + '>' : entry.address) : '')
        .filter(Boolean)
        .join(', ');
    }
    if (value.address) return value.name ? value.name + ' <' + value.address + '>' : String(value.address);
  }
  return String(value);
};

const parseDate = (value) => {
  const parsed = value ? new Date(value) : new Date();
  return Number.isNaN(parsed.getTime()) ? new Date() : parsed;
};

const senderEmail = extractEmail($json.from);
if (!senderEmail) {
  throw new Error('Incoming email did not include a parseable From address.');
}

if (senderEmail === ACCOUNT_EMAIL) {
  return [];
}

const textPlain = normalizeWhitespace($json.textPlain ?? $json.text ?? '');
const textHtml = normalizeWhitespace(stripHtml($json.textHtml ?? $json.html ?? $json.textAsHtml ?? ''));
const emailText = textPlain || textHtml;

if (!emailText) {
  throw new Error('Incoming email did not include a plain-text or HTML body to answer.');
}

const originalSubject = normalizeWhitespace($json.subject ?? '(no subject)');
const replySubject = /^\s*re:/i.test(originalSubject) ? originalSubject : 'Re: ' + originalSubject;
const messageId = normalizeWhitespace($json.metadata?.['message-id'] ?? $json.metadata?.messageId ?? $json.messageId ?? '');
const gmailId = normalizeWhitespace($json.id ?? '');
const gmailThreadId = normalizeWhitespace($json.threadId ?? '');
const imapUid = $json.attributes?.uid ?? null;
const receivedAt = parseDate($json.date).toISOString();
const messageKey = messageId || (gmailId ? 'gmail-id:' + gmailId : ('imap-uid:' + String(imapUid ?? 'none') + ':' + hashText([senderEmail, receivedAt, originalSubject, emailText].join('\n'))));
const senderRaw = formatAddress($json.from) || senderEmail;
const toRaw = formatAddress($json.to) || ACCOUNT_EMAIL;
const ccRaw = formatAddress($json.cc);

const fullEmail = [
  'From: ' + senderRaw,
  'To: ' + toRaw,
  'Date: ' + receivedAt,
  'Subject: ' + originalSubject,
  '',
  emailText,
].join('\n');

const emailPayload = {
  mailbox: ACCOUNT_EMAIL,
  account_email: ACCOUNT_EMAIL,
  sender_email: senderEmail,
  sender_raw: senderRaw,
  to_raw: toRaw,
  cc_raw: ccRaw,
  received_at: receivedAt,
  message_id: messageId,
  message_key: messageKey,
  original_subject: originalSubject,
  reply_subject: replySubject,
  email_text: emailText,
  full_email: fullEmail,
  imap_uid: imapUid,
  gmail_id: gmailId,
  gmail_thread_id: gmailThreadId,
};

return [{
  json: {
    ...emailPayload,
    email_payload: emailPayload,
    email_payload_sql: JSON.stringify(emailPayload).replace(/'/g, "''"),
  },
}];

if (!$json.should_reply) {
  return [];
}

const parsePayload = (value) => {
  if (!value) return {};
  if (typeof value === 'string') return JSON.parse(value);
  return value;
};

const emailPayload = parsePayload($json.email_payload);
emailPayload.top_k = Number($json.top_k ?? emailPayload.top_k ?? 5);
emailPayload.email_record_id = $json.email_record_id;

return [{
  json: {
    ...emailPayload,
    email_payload: emailPayload,
    email_payload_sql: JSON.stringify(emailPayload).replace(/'/g, "''"),
    top_k: emailPayload.top_k,
    email_record_id: $json.email_record_id,
  },
}];

const stripHtml = (value) => String(value)
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ');

const normalizeText = (value) => stripHtml(value)
  .replace(/\x60\x60\x60[\s\S]*?\x60\x60\x60/g, (block) => '\n' + block + '\n')
  .replace(/\r\n/g, '\n')
  .replace(/[\t ]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const chunkText = (text, maxLength = 1200, overlap = 180) => {
  if (!text) return [];
  const blocks = text.split(/\n(?=#{1,6}\s)|\n\n+/).map((block) => block.trim()).filter(Boolean);
  const chunks = [];
  let current = '';

  const pushCurrent = () => {
    const trimmed = current.trim();
    if (trimmed) chunks.push(trimmed);
    current = '';
  };

  for (const block of blocks) {
    if (block.length > maxLength) {
      pushCurrent();
      for (let start = 0; start < block.length; start += maxLength - overlap) {
        chunks.push(block.slice(start, start + maxLength).trim());
      }
      continue;
    }

    const candidate = current ? current + '\n\n' + block : block;
    if (candidate.length > maxLength) {
      pushCurrent();
      current = block;
    } else {
      current = candidate;
    }
  }

  pushCurrent();
  return chunks;
};

const emailPayload = $json.email_payload ?? $json;
const text = normalizeText(emailPayload.email_text ?? '');
const chunks = chunkText(text);

if (!chunks.length) {
  throw new Error('Email text produced zero chunks after normalization.');
}

return chunks.map((chunk, index) => ({
  json: {
    email_payload: emailPayload,
    email_payload_sql: $json.email_payload_sql ?? JSON.stringify(emailPayload).replace(/'/g, "''"),
    top_k: Number(emailPayload.top_k ?? 5),
    chunk_index: index,
    chunk_count: chunks.length,
    chunk_text: chunk,
  },
}));

const rows = $input.all().map((item) => item.json);
if (!rows.length) {
  throw new Error('No knowledge-base rows were scored. Run wikijs-embeddings-index before enabling the responder.');
}

const parsePayload = (value) => {
  if (!value) return {};
  if (typeof value === 'string') return JSON.parse(value);
  return value;
};

const emailPayload = parsePayload(rows[0].email_payload);
const topK = Number(rows[0].top_k ?? emailPayload.top_k ?? 5);
const bestByPage = new Map();

for (const row of rows) {
  if (!row.page_id) continue;
  const distance = Number(row.distance);
  if (!Number.isFinite(distance)) continue;

  const key = String(row.page_id);
  const current = bestByPage.get(key);
  if (!current || distance < current.best_distance) {
    bestByPage.set(key, {
      ...row,
      page_id: key,
      best_distance: distance,
    });
  }
}

const rankedPages = [...bestByPage.values()]
  .sort((a, b) => a.best_distance - b.best_distance);

if (!rankedPages.length) {
  throw new Error('No distinct Wiki.js pages were available. Run wikijs-embeddings-index before enabling the responder.');
}

const effectiveTopK = Math.min(topK, rankedPages.length);

return rankedPages.slice(0, effectiveTopK).map((page, index) => ({
  json: {
    email_payload: emailPayload,
    top_k: topK,
    available_page_count: rankedPages.length,
    returned_page_count: effectiveTopK,
    rank: index + 1,
    page_id: page.page_id,
    page_id_number: Number(page.page_id),
    path: page.path ?? '',
    title: page.title ?? page.path ?? ('Wiki.js page ' + page.page_id),
    wiki_url: page.wiki_url ?? null,
    best_distance: page.best_distance,
    matched_email_chunk_index: Number(page.email_chunk_index ?? 0),
    matched_chunk_index: Number(page.matched_chunk_index ?? 0),
    matched_chunk_text: page.matched_chunk_text ?? '',
  },
}));

const pageResponses = $input.all();
const rankedPages = $items('Rank top K pages').map((item) => item.json);

if (!rankedPages.length) {
  throw new Error('No ranked Wiki.js pages are available for the reply prompt.');
}

const emailPayload = rankedPages[0].email_payload;

const stripHtml = (value) => String(value ?? '')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ');

const normalizeText = (value) => stripHtml(value)
  .replace(/\x60\x60\x60[\s\S]*?\x60\x60\x60/g, (block) => '\n' + block + '\n')
  .replace(/\r\n/g, '\n')
  .replace(/[\t ]+/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

const contextPages = pageResponses.map((item, index) => {
  const response = item.json ?? {};
  if (Array.isArray(response.errors) && response.errors.length) {
    const messages = response.errors.map((error) => error.message).join('; ');
    throw new Error('Wiki.js page content GraphQL error: ' + messages);
  }

  const page = response.data?.pages?.single ?? response.pages?.single;
  if (!page) {
    throw new Error('Wiki.js returned no page content for a ranked page.');
  }

  const ranking = rankedPages[index] ?? rankedPages.find((candidate) => String(candidate.page_id) === String(page.id));
  const content = normalizeText(page.content || page.render || '');

  return {
    rank: ranking?.rank ?? index + 1,
    title: page.title ?? ranking?.title ?? page.path ?? ('Wiki.js page ' + page.id),
    path: page.path ?? ranking?.path ?? '',
    wiki_url: ranking?.wiki_url ?? null,
    best_distance: ranking?.best_distance ?? null,
    matched_email_chunk_index: ranking?.matched_email_chunk_index ?? null,
    matched_chunk_index: ranking?.matched_chunk_index ?? null,
    content,
  };
});

const knowledgeBaseContext = contextPages
  .sort((a, b) => a.rank - b.rank)
  .map((page) => [
    '## ' + page.rank + '. ' + page.title,
    'Path: ' + page.path,
    page.wiki_url ? 'URL: ' + page.wiki_url : null,
    page.best_distance !== null ? 'Best embedding distance: ' + page.best_distance : null,
    page.matched_email_chunk_index !== null ? 'Matched email chunk: ' + page.matched_email_chunk_index : null,
    page.matched_chunk_index !== null ? 'Matched KB chunk: ' + page.matched_chunk_index : null,
    '',
    page.content,
  ].filter((line) => line !== null).join('\n'))
  .join('\n\n---\n\n');

const prompt = [
  'You are replying on behalf of Wieland Collective from ' + emailPayload.account_email + '.',
  '',
  'Write a helpful email reply to the sender. Use the Wiki.js knowledge-base pages below as the factual context for the reply. Do not invent details that are not supported by the context or the incoming email. If the context does not answer a specific question, say that we will follow up. Keep the tone warm, concise, and professional. Match the incoming email language when practical. Return only the email body; do not include a subject line, markdown code fence, or analysis.',
  '',
  '# Retrieved Wiki.js Context (' + contextPages.length + ' distinct pages)',
  knowledgeBaseContext,
  '',
  '# Incoming Email',
  emailPayload.full_email,
  '',
  '# Reply Body',
].join('\n');

return [{
  json: {
    email_payload: emailPayload,
    to_email: emailPayload.sender_email,
    from_email: emailPayload.account_email,
    reply_subject: emailPayload.reply_subject,
    original_subject: emailPayload.original_subject,
    prompt,
    matched_pages: contextPages,
  },
}];

const promptItem = $items('Build reply prompt')[0]?.json;
if (!promptItem) {
  throw new Error('Missing reply prompt context.');
}

const output = $json.output;
let replyBody = '';

if (Array.isArray(output)) {
  replyBody = output
    .flatMap((entry) => entry.content ?? [])
    .map((content) => content.text ?? '')
    .join('\n')
    .trim();
} else if (typeof output === 'string') {
  replyBody = output.trim();
} else if ($json.output_text) {
  replyBody = String($json.output_text).trim();
} else if ($json.text) {
  replyBody = String($json.text).trim();
}

if (!replyBody) {
  throw new Error('GPT returned an empty email reply.');
}

return [{
  json: {
    ...promptItem,
    reply_body: replyBody,
  },
}];
